const input = $input.first().json;
const body = input.body || input;
const creator = body.creator || {};

if (body.action === 'send' || body.allowSend === true || body.dryRun === false) {
  return [{
    json: {
      ok: false,
      status: 'blocked',
      queueId: body.queueId || '',
      dryRun: true,
      allowSend: false,
      source: 'n8n-dry-run',
      message: 'Automatic outreach sending is disabled. Generate a draft first.',
      updatedAt: new Date().toISOString(),
    },
  }];
}

const name = creator.displayName || creator.handle || 'there';
const handle = String(creator.handle || '').replace(/^@/, '');
const keywords = Array.isArray(creator.matchedKeywords) ? creator.matchedKeywords.slice(0, 4) : [];
const metrics = creator.metrics || {};
const videos = creator.evidence?.recentVideos || [];
const nicheLine = keywords.length
  ? `Your content fits our ${keywords.join(' / ')} creator list.`
  : 'Your beauty and hair content fits our creator list.';
const profileLine = handle ? `I found your TikTok @${handle}` : 'I found your TikTok profile';
const proof = [
  metrics.followers ? `${metrics.followers} followers` : '',
  metrics.avgViews30d ? `${metrics.avgViews30d} avg views in 30 days` : '',
  metrics.productVideoCount ? `${metrics.productVideoCount} commerce/product signals` : '',
].filter(Boolean).join(', ');
const proofLine = proof ? ` The EchoTik evidence I checked: ${proof}.` : '';
const videoLine = videos.length ? ` I also checked ${videos.length} recent/high-play videos before drafting this.` : '';

const draft = [
  `Hi ${name},`,
  '',
  `${profileLine} and liked the way your hair content connects with your audience. ${nicheLine}${proofLine}${videoLine}`,
  '',
  'We are preparing a first collaboration wave for drawstring ponytail, half wig, crochet hair, and braids products. The starting offer is free product + paid collaboration + commission, with TikTok Shop videos as the main deliverable.',
  '',
  'Would you be open to reviewing the details if the product style matches your audience?',
  '',
  'Best regards',
  'TK-SaaS Creator Team',
].join('\n');

return [{
  json: {
    ok: true,
    queueId: body.queueId || '',
    status: 'draft_ready',
    source: 'n8n-dry-run',
    draft,
    dryRun: true,
    allowSend: false,
    creatorId: creator.id || '',
    creatorHandle: handle,
    videosChecked: videos.length,
    updatedAt: new Date().toISOString(),
  },
}];
